refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
gray = rgb2gray(image);
mask = gray < 230;
clean = imclearborder(mask, 8);
removed = mask & ~clean;

classified = imoverlaymask(image, clean .* 1, [0 255 0], 0.35, %t);
classified = imoverlaymask(classified, removed .* 1, [255 0 0], 0.65, %t);

subplot(1, 3, 1);
imshow(image);
xtitle("Original image");
subplot(1, 3, 2);
imshow(uint8(mask .* 255));
xtitle("Thresholded objects");
subplot(1, 3, 3);
imshow(classified);
xtitle("Green: kept; red: removed");
